public uint ReadUInt32()
        {
            if (IsReadOnlySequenceInput || IsSpanInput || IsBufferSliceInput || IsArcBufferInput)
            {
                const int width = 4;
                if (_bufferPos + width > _bufferSize)
                {
                    return ReadSlower(ref this);
                }

                var result = BinaryPrimitives.ReadUInt32LittleEndian(_currentSpan.Slice(_bufferPos, width));
                _bufferPos += width;
                return result;

                static uint ReadSlower(ref Reader<TInput> r)
                {
                    uint b1 = r.ReadByte();
                    uint b2 = r.ReadByte();
                    uint b3 = r.ReadByte();
                    uint b4 = r.ReadByte();

                    return b1 | (b2 << 8) | (b3 << 16) | (b4 << 24);
                }
            }
            else if (_input is ReaderInput readerInput)
            {
                return readerInput.ReadUInt32();
            }
            else
            {
                return ThrowNotSupportedInput<uint>();
            }
        }

void IFieldCodec<BitArray>.WriteField<TBufferWriter>(ref Writer<TBufferWriter> writer, uint fieldIdDelta, Type expectedType, BitArray value)
        {
            if (ReferenceCodec.TryWriteReferenceField(ref writer, fieldIdDelta, expectedType, value))
            {
                return;
            }

            writer.WriteFieldHeader(fieldIdDelta, expectedType, typeof(BitArray), WireType.LengthPrefixed);

#if NET10_0_OR_GREATER
            var bytes = CollectionsMarshal.AsBytes(value);
            writer.WriteVarUInt32((uint)bytes.Length);
            writer.Write(bytes);
#else
            var numBytes = GetByteArrayLengthFromBitLength(value.Length);
            writer.WriteVarUInt32((uint)numBytes);
            writer.Write(MemoryMarshal.AsBytes(GetSetArray(value).AsSpan()).Slice(0, numBytes));
#endif

#if !NET10_0_OR_GREATER
            static int GetByteArrayLengthFromBitLength(int n)
            {
                const int BitShiftPerByte = 3;
                Debug.Assert(n >= 0);
                return (int)((uint)(n - 1 + (1 << BitShiftPerByte)) >> BitShiftPerByte);
            }
#endif
        }

public (T1, T2, T3, T4, T5) ReadValue<TInput>(ref Reader<TInput> reader, Field field)
        {
            field.EnsureWireTypeTagDelimited();
            ReferenceCodec.MarkValueField(reader.Session);
            (T1, T2, T3, T4, T5) res = default;
            uint fieldId = 0;
            while (true)
            {
                var header = reader.ReadFieldHeader();
                if (header.IsEndBaseOrEndObject)
                {
                    break;
                }

                fieldId += header.FieldIdDelta;
                switch (fieldId)
                {
                    case 1: res.Item1 = _item1Codec.ReadValue(ref reader, header); break;
                    case 2: res.Item2 = _item2Codec.ReadValue(ref reader, header); break;
                    case 3: res.Item3 = _item3Codec.ReadValue(ref reader, header); break;
                    case 4: res.Item4 = _item4Codec.ReadValue(ref reader, header); break;
                    case 5: res.Item5 = _item5Codec.ReadValue(ref reader, header); break;
                    default:
                        reader.ConsumeUnknownField(header);
                        break;
                }
            }

            return res;
        }

